using UnityEngine;

/// <summary>É actualmente este período do dia.</summary>
[System.Serializable]
public class Condition_TimeOfDay : NpcCondition
{
    public TimeOfDay timeOfDay = TimeOfDay.Manha;

    public override bool Evaluate(NpcController npc)
    {
        return WorldState.Instance != null && WorldState.Instance.IsTimeOfDay(timeOfDay);
    }
}

/// <summary>O clima actual é este.</summary>
[System.Serializable]
public class Condition_Weather : NpcCondition
{
    public WeatherType weather = WeatherType.Limpo;

    public override bool Evaluate(NpcController npc)
    {
        return WorldState.Instance != null && WorldState.Instance.IsWeather(weather);
    }
}

/// <summary>O mundo actual do player é este.</summary>
[System.Serializable]
public class Condition_CurrentWorld : NpcCondition
{
    public WorldData world;

    public override bool Evaluate(NpcController npc)
    {
        return WorldState.Instance != null && WorldState.Instance.IsCurrentWorld(world);
    }
}

/// <summary>A área actual do player é esta.</summary>
[System.Serializable]
public class Condition_CurrentArea : NpcCondition
{
    public AreaData area;

    public override bool Evaluate(NpcController npc)
    {
        return WorldState.Instance != null && WorldState.Instance.IsCurrentArea(area);
    }
}

/// <summary>O boss deste mundo já foi derrotado.</summary>
[System.Serializable]
public class Condition_BossDefeated : NpcCondition
{
    public WorldData world;

    [Tooltip("true = condição cumpre-se quando o boss JÁ foi derrotado; false = quando ainda NÃO foi.")]
    public bool mustBeDefeated = true;

    public override bool Evaluate(NpcController npc)
    {
        if (PlayerProgress.Instance == null) return false;
        return PlayerProgress.Instance.HasDefeatedBoss(world) == mustBeDefeated;
    }
}

/// <summary>Compara a população actual de uma vila.</summary>
[System.Serializable]
public class Condition_VillagePopulation : NpcCondition
{
    public string villageId;
    public Comparison comparison = Comparison.GreaterOrEqual;
    public int amount = 1;

    public override bool Evaluate(NpcController npc)
    {
        if (WorldState.Instance == null) return false;

        var pop = WorldState.Instance.GetVillagePopulation(villageId);
        int current = pop != null ? pop.current : 0;

        return NpcConditionUtil.Compare(current, comparison, amount);
    }
}

/// <summary>Esta área já foi (ou ainda não foi) visitada pelo player.</summary>
[System.Serializable]
public class Condition_AreaVisited : NpcCondition
{
    public AreaData area;

    [Tooltip("true = condição cumpre-se se a área JÁ foi visitada; false = se ainda NÃO foi.")]
    public bool mustBeVisited = true;

    public override bool Evaluate(NpcController npc)
    {
        if (PlayerProgress.Instance == null) return false;
        return PlayerProgress.Instance.HasVisited(area) == mustBeVisited;
    }
}

/// <summary>É a primeira vez que o player visita esta área.</summary>
[System.Serializable]
public class Condition_FirstVisit : NpcCondition
{
    public AreaData area;

    public override bool Evaluate(NpcController npc)
    {
        return PlayerProgress.Instance != null && PlayerProgress.Instance.IsFirstVisit(area);
    }
}
